(function () {
  function debounce(fn, delay) {
    var t;
    return function () {
      var ctx = this, args = arguments;
      clearTimeout(t);
      t = setTimeout(function () { fn.apply(ctx, args); }, delay);
    };
  }

  function getDelay(trigger) {
    var match = (trigger || "").match(/delay:(\d+)ms/);
    return match ? parseInt(match[1], 10) : 300;
  }

  function attach(el) {
    var url = el.getAttribute("hx-get");
    var targetSel = el.getAttribute("hx-target");
    if (!url || !targetSel) return;
    var trigger = el.getAttribute("hx-trigger") || "keyup";
    var delay = getDelay(trigger);
    var handler = debounce(function () {
      var q = encodeURIComponent(el.value || "");
      var fetchUrl = url + (url.indexOf("?") === -1 ? "?q=" : "&q=") + q;
      fetch(fetchUrl, { headers: { "HX-Request": "true" } })
        .then(function (r) { return r.text(); })
        .then(function (html) {
          var target = document.querySelector(targetSel);
          if (target) target.innerHTML = html;
        });
    }, delay);

    if (trigger.indexOf("keyup") !== -1) {
      el.addEventListener("keyup", handler);
    }
    if (trigger.indexOf("changed") !== -1) {
      el.addEventListener("change", handler);
    }
  }

  document.addEventListener("DOMContentLoaded", function () {
    var elements = document.querySelectorAll("[hx-get]");
    elements.forEach(attach);
  });
})();
